INSERT INTO fichas_ciudad (ciudad, pais, idioma, moneda, moneda_simbolo, tipo_enchufe, zona_horaria, emergencias, visa_info, fecha_llegada, fecha_salida, noches, como_llegar_aeropuerto, tips_transporte) VALUES ('Londres', 'Reino Unido', 'Inglés', 'Libra esterlina (GBP)', '£', 'Tipo G — tres pines planos', 'GMT / UTC+0', '{"todos":"999"}', 'ETA requerida — tramitar antes del viaje', '2027-01-29', '2027-02-02', 4, 'Desde LHR tomar Underground Piccadilly Line hasta Piccadilly Circus o Leicester Square. NO tomar la Elizabeth Line. Marcar la tarjeta al entrar Y al salir.', ARRAY['Oyster card o contactless. Marcar al ENTRAR y al SALIR — sin salida se cobra tarifa maxima.','Desde LHR: Piccadilly Line. NO tomar la Elizabeth Line.','El bus es mas barato que el tube y permite ver la ciudad.']);
INSERT INTO fichas_ciudad (ciudad, pais, idioma, moneda, moneda_simbolo, tipo_enchufe, zona_horaria, emergencias, visa_info, fecha_llegada, fecha_salida, noches, como_llegar_aeropuerto, tips_transporte) VALUES ('Paris', 'Francia', 'Francés', 'Euro (EUR)', '€', 'Tipo C/E — dos pines redondos', 'CET / UTC+1', '{"todos":"112","policía":"17","ambulancia":"15","bomberos":"18"}', 'ETIAS requerido (Espacio Schengen)', '2027-02-02', '2027-02-06', 4, 'Desde CDG tomar RER B hasta centro. Marcar al entrar Y al salir.', ARRAY['Marcar al ENTRAR y al SALIR en metro y RER.','Navigo Decouverte semanal conviene si se usa mucho el transporte.','RER B desde CDG directo al centro.']);
INSERT INTO fichas_ciudad (ciudad, pais, idioma, moneda, moneda_simbolo, tipo_enchufe, zona_horaria, emergencias, visa_info, fecha_llegada, fecha_salida, noches, como_llegar_aeropuerto, tips_transporte) VALUES ('Bruselas', 'Bélgica', 'Francés / Neerlandés / Alemán', 'Euro (EUR)', '€', 'Tipo C/E — dos pines redondos', 'CET / UTC+1', '{"todos":"112","policía":"101","ambulancia":"100"}', 'ETIAS requerido (Espacio Schengen)', '2027-02-06', '2027-02-07', 1, 'Desde BRU tomar tren directo a Bruxelles-Central. Marcar siempre aunque no haya control visible.', ARRAY['Marcar SIEMPRE aunque no haya molinete ni control visible — multa si no se valida.','Tren directo desde BRU a Bruxelles-Central cada 15 min.']);
INSERT INTO fichas_ciudad (ciudad, pais, idioma, moneda, moneda_simbolo, tipo_enchufe, zona_horaria, emergencias, visa_info, fecha_llegada, fecha_salida, noches, como_llegar_aeropuerto, tips_transporte) VALUES ('Roma', 'Italia', 'Italiano', 'Euro (EUR)', '€', 'Tipo C/F/L — pines redondos', 'CET / UTC+1', '{"todos":"112","policía":"113","ambulancia":"118","bomberos":"115"}', 'ETIAS requerido (Espacio Schengen)', '2027-02-07', '2027-02-11', 4, 'Desde FCO: traslado privado con Monza/Downtown Travel. Alternativa: Leonardo Express hasta Roma Termini.', ARRAY['Validar el ticket al subir al bus o tranvia — inspectores frecuentes.','Traslado FCO: Monza/Downtown Travel (a confirmar).','Leonardo Express: FCO a Roma Termini en 32 min, cada 30 min.']);
INSERT INTO fichas_ciudad (ciudad, pais, idioma, moneda, moneda_simbolo, tipo_enchufe, zona_horaria, emergencias, visa_info, fecha_llegada, fecha_salida, noches, como_llegar_aeropuerto, tips_transporte) VALUES ('Madrid', 'España', 'Español', 'Euro (EUR)', '€', 'Tipo C/F — dos pines redondos', 'CET / UTC+1', '{"todos":"112","policía":"091","ambulancia":"061"}', 'ETIAS requerido (Espacio Schengen)', '2027-02-11', '2027-02-15', 4, 'Metro Linea 8 (rosa) hasta Nuevos Ministerios + transbordo. O taxi directo ~30 min.', ARRAY['Metro Linea 8 desde aeropuerto requiere suplemento aeropuerto (~EUR 3).','Tarjeta Multi de 10 viajes conviene para el grupo.']);
