INSERT INTO lugares (ciudad, categoria, nombre, zona, descripcion, precio, es_gratis, requiere_reserva, tip, maps_url) VALUES ('Londres', 'miradores', 'Sky Garden', 'City of London', 'Jardin en la cima del 20 Fenchurch St con vista panoramica de 360 sobre la City.', 'Gratis', true, true, 'Reservar antes del viaje — se agota rapido.', 'https://maps.google.com/?q=Sky+Garden+London');
INSERT INTO lugares (ciudad, categoria, nombre, zona, descripcion, precio, es_gratis, requiere_reserva, tip, maps_url) VALUES ('Londres', 'miradores', 'One New Change — Rooftop', 'City of London', 'Terraza abierta directamente frente a St Paul''s Cathedral. Vista frontal sin obstaculos. Sin costo, sin reserva.', 'Gratis', true, false, 'Acceso libre todo el dia.', 'https://maps.google.com/?q=One+New+Change+London');
INSERT INTO lugares (ciudad, categoria, nombre, zona, descripcion, precio, es_gratis, requiere_reserva, tip, maps_url) VALUES ('Londres', 'miradores', 'Tate Modern — Terraza nivel 10', 'South Bank', 'Mirador gratuito con vistas del Tamesis, St Paul''s y el Millennium Bridge.', 'Gratis', true, false, 'Ideal al atardecer.', 'https://maps.google.com/?q=Tate+Modern+London');
INSERT INTO lugares (ciudad, categoria, nombre, zona, descripcion, precio, es_gratis, requiere_reserva, tip, maps_url) VALUES ('Londres', 'miradores', 'Greenwich Park — Royal Observatory', 'Greenwich', 'Colina del Observatorio Real. El Meridiano de Greenwich cruza aqui.', 'Gratis', true, false, 'Llevar termo — frio en febrero.', 'https://maps.google.com/?q=Royal+Observatory+Greenwich');
INSERT INTO lugares (ciudad, categoria, nombre, zona, descripcion, precio, es_gratis, requiere_reserva, tip, maps_url) VALUES ('Londres', 'miradores', 'The Shard — Viewing Gallery', 'London Bridge', 'El punto mas alto de Londres. Piso 68-69 al aire libre.', 'Pago ~£32', false, true, 'Mejor de noche.', 'https://maps.google.com/?q=The+Shard+London');
INSERT INTO lugares (ciudad, categoria, nombre, zona, descripcion, precio, es_gratis, requiere_reserva, tip, maps_url) VALUES ('Londres', 'miradores', 'Primrose Hill', 'Primrose Hill', 'Colina con panoramica del skyline. Ambiente local, sin turistas.', 'Gratis', true, false, 'A 10 min de Camden.', 'https://maps.google.com/?q=Primrose+Hill+London');
INSERT INTO lugares (ciudad, categoria, nombre, zona, descripcion, precio, es_gratis, requiere_reserva, tip, maps_url) VALUES ('Londres', 'miradores', 'Monument to the Great Fire', 'City of London', '311 escalones hasta la cupula con vistas del centro historico.', 'Pago ~£6', false, false, 'Hay diploma al llegar arriba — les encanta a los chicos.', 'https://maps.google.com/?q=Monument+London');
INSERT INTO lugares (ciudad, categoria, nombre, zona, descripcion, precio, es_gratis, requiere_reserva, tip, maps_url) VALUES ('Londres', 'bares', 'Lamb & Flag', 'Covent Garden', 'Pub historico de 1772 en callejon adoquinado.', 'Consumicion ~£6-8 pinta', false, false, 'El pub que todo londinense ama mostrar.', 'https://maps.google.com/?q=Lamb+and+Flag+Covent+Garden+London');
INSERT INTO lugares (ciudad, categoria, nombre, zona, descripcion, precio, es_gratis, requiere_reserva, tip, maps_url) VALUES ('Londres', 'bares', 'Swift Bar', 'Soho', 'Bar de cocteles de dos niveles. Whisky y clasicos. Solo adultos.', 'Cocteles ~£14-18', false, false, 'Para la noche sin los chicos.', 'https://maps.google.com/?q=Swift+Bar+Soho+London');
INSERT INTO lugares (ciudad, categoria, nombre, zona, descripcion, precio, es_gratis, requiere_reserva, tip, maps_url) VALUES ('Londres', 'bares', 'Anchor Bankside', 'South Bank', 'Pub historico sobre el Tamesis frente al Tate Modern.', 'Consumicion ~£6-8 pinta', false, false, 'Terraza sobre el rio — llevar abrigo.', 'https://maps.google.com/?q=Anchor+Bankside+London');
INSERT INTO lugares (ciudad, categoria, nombre, zona, descripcion, precio, es_gratis, requiere_reserva, tip, maps_url) VALUES ('Londres', 'bares', 'Nightjar', 'Shoreditch', 'Speakeasy subterraneo. Jazz en vivo jue-dom. World''s 50 Best.', 'Cocteles ~£16-22', false, true, 'Reservar semanas antes. Dress code elegante.', 'https://maps.google.com/?q=Nightjar+Bar+London');
INSERT INTO lugares (ciudad, categoria, nombre, zona, descripcion, precio, es_gratis, requiere_reserva, tip, maps_url) VALUES ('Londres', 'bares', 'The Blues Kitchen Camden', 'Camden', 'BBQ americano y musica en vivo: blues, soul, R&B. Ideal para grupos.', 'Sin entrada · Consumicion ~£8-12', false, false, 'Perfecto para todos juntos.', 'https://maps.google.com/?q=Blues+Kitchen+Camden+London');
INSERT INTO lugares (ciudad, categoria, nombre, zona, descripcion, precio, es_gratis, requiere_reserva, tip, maps_url) VALUES ('Londres', 'bares', 'Dukes Bar', 'Mayfair', 'Bar que inspiro los martinis de James Bond. Se preparan en carrito junto a la mesa.', 'Martini ~£25-30', false, false, 'Solo un martini — son brutalmente fuertes.', 'https://maps.google.com/?q=Dukes+Bar+London');
INSERT INTO lugares (ciudad, categoria, nombre, zona, descripcion, precio, es_gratis, requiere_reserva, tip, maps_url) VALUES ('Londres', 'bares', 'The Market Porter', 'Borough Market', 'Pub victoriano junto al mercado. Aparece en Harry Potter.', 'Consumicion ~£6-8 pinta', false, false, 'Combinarlo con el Borough Market.', 'https://maps.google.com/?q=The+Market+Porter+London');
INSERT INTO lugares (ciudad, categoria, nombre, zona, descripcion, precio, es_gratis, requiere_reserva, tip, maps_url) VALUES ('Londres', 'iconicos', 'Tower of London', 'City of London', 'Fortaleza medieval con las Joyas de la Corona y guardias Beefeater.', 'Pago ~£34 adulto / £17 nino', false, true, 'Tickets online con anticipacion.', 'https://maps.google.com/?q=Tower+of+London');
INSERT INTO lugares (ciudad, categoria, nombre, zona, descripcion, precio, es_gratis, requiere_reserva, tip, maps_url) VALUES ('Londres', 'iconicos', 'Westminster Abbey', 'Westminster', 'Catedral de las coronaciones. Enterrados Darwin, Newton, Dickens.', 'Pago ~£27 adulto', false, true, 'Reservar online.', 'https://maps.google.com/?q=Westminster+Abbey+London');
INSERT INTO lugares (ciudad, categoria, nombre, zona, descripcion, precio, es_gratis, requiere_reserva, tip, maps_url) VALUES ('Londres', 'iconicos', 'British Museum', 'Bloomsbury', 'Piedra Rosetta, momias egipcias, esculturas del Partenon.', 'Gratis', true, true, 'Entrar por Montague Place (puerta trasera) — menos cola.', 'https://maps.google.com/?q=British+Museum+London');
INSERT INTO lugares (ciudad, categoria, nombre, zona, descripcion, precio, es_gratis, requiere_reserva, tip, maps_url) VALUES ('Londres', 'iconicos', 'Shakespeare''s Globe', 'South Bank', 'Replica del teatro isabelino. Tour disponible. Funciones en febrero.', 'Tour ~£18 / Funcion desde £5 (standing)', false, false, 'Ver cartelera de febrero.', 'https://maps.google.com/?q=Shakespeare+Globe+London');
INSERT INTO lugares (ciudad, categoria, nombre, zona, descripcion, precio, es_gratis, requiere_reserva, tip, maps_url) VALUES ('Londres', 'iconicos', 'Portobello Road Market', 'Notting Hill', 'Mercado de antiguedades y vintage. Sabados es el dia fuerte.', 'Entrada gratis', true, false, '1 feb es sabado — perfecto.', 'https://maps.google.com/?q=Portobello+Road+Market+London');
INSERT INTO lugares (ciudad, categoria, nombre, zona, descripcion, precio, es_gratis, requiere_reserva, tip, maps_url) VALUES ('Londres', 'iconicos', 'Camden Market', 'Camden', 'Mercado alternativo con food hall, ropa, viniles, artesanias.', 'Entrada gratis', true, false, 'Con adolescentes es el favorito.', 'https://maps.google.com/?q=Camden+Market+London');
INSERT INTO lugares (ciudad, categoria, nombre, zona, descripcion, precio, es_gratis, requiere_reserva, tip, maps_url) VALUES ('Londres', 'iconicos', 'Natural History Museum', 'South Kensington', 'Dinosaurio gigante en el hall. Fascinante para todas las edades.', 'Gratis', true, true, 'Puede quedar pista de hielo en febrero. Reservar para evitar fila.', 'https://maps.google.com/?q=Natural+History+Museum+London');
INSERT INTO lugares (ciudad, categoria, nombre, zona, descripcion, precio, es_gratis, requiere_reserva, tip, maps_url) VALUES ('Londres', 'iconicos', 'Columbia Road Flower Market', 'East London', 'Solo domingos. Mercado de flores en calle victoriana estrecha.', 'Entrada gratis', true, false, 'Ir temprano — abre 8am y se llena al mediodia.', 'https://maps.google.com/?q=Columbia+Road+Flower+Market+London');
INSERT INTO lugares (ciudad, categoria, nombre, zona, descripcion, precio, es_gratis, requiere_reserva, tip, maps_url) VALUES ('Londres', 'musica', 'Ronnie Scott''s Jazz Club', 'Soho', 'El club de jazz mas famoso del mundo desde 1959. Miles Davis, Amy Winehouse tocaron aqui.', 'Entrada ~£35-60', false, true, 'Reservar — sold out frecuente.', 'https://maps.google.com/?q=Ronnie+Scotts+London');
INSERT INTO lugares (ciudad, categoria, nombre, zona, descripcion, precio, es_gratis, requiere_reserva, tip, maps_url) VALUES ('Londres', 'musica', 'Electric Ballroom', 'Camden', 'Sala emblematica de Camden. Rock, indie, electronica. Noche retro los sabados.', 'Entrada ~£10-20', false, false, 'Revisar agenda en febrero.', 'https://maps.google.com/?q=Electric+Ballroom+Camden+London');
INSERT INTO lugares (ciudad, categoria, nombre, zona, descripcion, precio, es_gratis, requiere_reserva, tip, maps_url) VALUES ('Londres', 'musica', 'Royal Festival Hall', 'South Bank', 'Sala del Southbank Centre. Bar exterior con vista al Tamesis, libre y gratuito.', 'Bar gratis · Concierto varia', true, false, 'Revisar programa en southbankcentre.co.uk', 'https://maps.google.com/?q=Royal+Festival+Hall+London');
INSERT INTO lugares (ciudad, categoria, nombre, zona, descripcion, precio, es_gratis, requiere_reserva, tip, maps_url) VALUES ('Londres', 'musica', '100 Club', 'Soho', 'Sala donde tocaron Rolling Stones, Sex Pistols y Oasis.', 'Entrada ~£10-20', false, false, 'Tickets baratos, ambiente autentico.', 'https://maps.google.com/?q=100+Club+Oxford+Street+London');
INSERT INTO lugares (ciudad, categoria, nombre, zona, descripcion, precio, es_gratis, requiere_reserva, tip, maps_url) VALUES ('Londres', 'musica', 'Royal Opera House', 'Covent Garden', 'Opera y ballet. Cafeteria abierta al publico sin entrada.', 'Cafeteria gratis · Funcion desde £5 (standing)', true, false, 'Standing disponible el dia de la funcion.', 'https://maps.google.com/?q=Royal+Opera+House+London');
INSERT INTO lugares (ciudad, categoria, nombre, zona, descripcion, precio, es_gratis, requiere_reserva, tip, maps_url) VALUES ('Londres', 'musica', 'O2 Academy Brixton', 'Brixton', '5000 personas, acustica perfecta. Shows internacionales frecuentes.', 'Entrada varia segun artista', false, false, 'Ver agenda en febrero.', 'https://maps.google.com/?q=O2+Academy+Brixton+London');
INSERT INTO lugares (ciudad, categoria, nombre, zona, descripcion, precio, es_gratis, requiere_reserva, tip, maps_url) VALUES ('Paris', 'miradores', 'Torre Eiffel', 'Champ de Mars', 'El icono de Paris. Tres pisos con vistas legendarias. 330m de altura, construida en 1889 para la Exposicion Universal.', 'Pago ~EUR 29 adulto / EUR 7.50 nino', false, true, 'Reservar con meses de anticipacion — sold out habitual.', 'https://maps.google.com/?q=Tour+Eiffel+Paris');
INSERT INTO lugares (ciudad, categoria, nombre, zona, descripcion, precio, es_gratis, requiere_reserva, tip, maps_url) VALUES ('Paris', 'miradores', 'Arc de Triomphe — Terraza', 'Champs-Elysees', 'Subir al arco (284 escalones) para vista sobre los 12 bulevares que irradian desde la Place de l''Etoile.', 'Pago ~EUR 13 adulto / Gratis -18', true, false, 'Al atardecer los bulevares iluminados son impresionantes.', 'https://maps.google.com/?q=Arc+de+Triomphe+Paris');
INSERT INTO lugares (ciudad, categoria, nombre, zona, descripcion, precio, es_gratis, requiere_reserva, tip, maps_url) VALUES ('Paris', 'miradores', 'Sacre-Coeur — Butte Montmartre', 'Montmartre', 'La basilica blanca sobre la colina mas alta de Paris. Vista 30km en dia claro. La escalinata es parte del paisaje.', 'Gratis', true, false, 'Ir temprano para evitar el gentio en las escaleras.', 'https://maps.google.com/?q=Sacre+Coeur+Montmartre+Paris');
INSERT INTO lugares (ciudad, categoria, nombre, zona, descripcion, precio, es_gratis, requiere_reserva, tip, maps_url) VALUES ('Paris', 'miradores', 'Centre Pompidou — Terraza', 'Beaubourg', 'Museo de arte contemporaneo con terraza en el techo. Vista sobre los tejados del Marais y Notre-Dame.', 'Pago entrada museo ~EUR 15 (incluye terraza)', false, false, 'El edificio de colores primarios en si es arquitectura iconica.', 'https://maps.google.com/?q=Centre+Pompidou+Paris');
INSERT INTO lugares (ciudad, categoria, nombre, zona, descripcion, precio, es_gratis, requiere_reserva, tip, maps_url) VALUES ('Paris', 'bares', 'Cafe de Flore', 'Saint-Germain-des-Pres', 'Cafe historico de 1887. Sartre y Simone de Beauvoir escribian aqui. El croissant y cafe con leche mas fotografiado de Paris.', 'Cafe ~EUR 5 / Plato ~EUR 18-25', false, false, 'Ir a desayunar, no de noche — la magia es el ambiente diurno.', 'https://maps.google.com/?q=Cafe+de+Flore+Paris');
INSERT INTO lugares (ciudad, categoria, nombre, zona, descripcion, precio, es_gratis, requiere_reserva, tip, maps_url) VALUES ('Paris', 'bares', 'Harry''s New York Bar', 'Opera', 'Fundado en 1911. Aqui nacieron el Bloody Mary y el club sandwich. Frecuentado por Hemingway y Gershwin.', 'Cocteles ~EUR 16-22', false, false, 'Pedir el Bloody Mary original — la receta es de este bar.', 'https://maps.google.com/?q=Harrys+New+York+Bar+Paris');
INSERT INTO lugares (ciudad, categoria, nombre, zona, descripcion, precio, es_gratis, requiere_reserva, tip, maps_url) VALUES ('Paris', 'bares', 'Le Mary Celeste', 'Marais', 'Cocktail bar de culto en el corazon del Marais. Ostras frescas y mezcales de autor.', 'Cocteles ~EUR 14-18', false, false, 'Llegar antes de las 20hs o hay fila.', 'https://maps.google.com/?q=Le+Mary+Celeste+Paris');
INSERT INTO lugares (ciudad, categoria, nombre, zona, descripcion, precio, es_gratis, requiere_reserva, tip, maps_url) VALUES ('Paris', 'bares', 'Caveau de la Huchette', 'Quartier Latin', 'Jazz y swing en vivo en bodega medieval del s.XIII desde 1946. El club mas antiguo de Paris.', 'Entrada ~EUR 15 / Consumicion adicional', false, false, 'Hay que bailar — los parisinos van a bailar swing, no solo a escuchar.', 'https://maps.google.com/?q=Caveau+de+la+Huchette+Paris');
INSERT INTO lugares (ciudad, categoria, nombre, zona, descripcion, precio, es_gratis, requiere_reserva, tip, maps_url) VALUES ('Paris', 'iconicos', 'Musee du Louvre', '1er arrondissement', 'El museo mas visitado del mundo. Mona Lisa, Venus de Milo, codigo Hammurabi. 35.000 obras.', 'Pago EUR 22 / Gratis -18', true, true, 'Reservar obligatorio — colas de horas sin reserva. Gratis menores de 18.', 'https://maps.google.com/?q=Louvre+Paris');
INSERT INTO lugares (ciudad, categoria, nombre, zona, descripcion, precio, es_gratis, requiere_reserva, tip, maps_url) VALUES ('Paris', 'iconicos', 'Notre-Dame de Paris', 'Ile de la Cite', 'Catedral gotica del siglo XII, reabierta en diciembre 2024 tras el incendio de 2019. Completamente restaurada.', 'Gratis exterior / Pago interior (con reserva)', true, true, 'Reservar online — afluencia masiva tras la reapertura.', 'https://maps.google.com/?q=Notre-Dame+Paris');
INSERT INTO lugares (ciudad, categoria, nombre, zona, descripcion, precio, es_gratis, requiere_reserva, tip, maps_url) VALUES ('Paris', 'iconicos', 'Musee d''Orsay', '7eme arrondissement', 'La coleccion impresionista mas importante del mundo en una antigua estacion de tren. Monet, Renoir, Van Gogh, Degas.', 'Pago EUR 16 / Gratis -18', true, true, 'Dedicarle minimo 3 horas. Los Van Gogh en el 5to piso son una revelacion.', 'https://maps.google.com/?q=Musee+Orsay+Paris');
INSERT INTO lugares (ciudad, categoria, nombre, zona, descripcion, precio, es_gratis, requiere_reserva, tip, maps_url) VALUES ('Paris', 'iconicos', 'Le Marais', '3eme y 4eme arrondissement', 'Barrio historico judio con galerias, tiendas vintage, la Place des Vosges (la plaza mas antigua de Paris) y el mejor falafel de Europa.', 'Gratis', true, false, 'El falafel de L''As du Fallafel en Rue des Rosiers vale la visita.', 'https://maps.google.com/?q=Le+Marais+Paris');
INSERT INTO lugares (ciudad, categoria, nombre, zona, descripcion, precio, es_gratis, requiere_reserva, tip, maps_url) VALUES ('Paris', 'iconicos', 'Versailles', 'Versailles (30 min en RER)', 'El palacio barroco de Luis XIV y los jardines de Le Notre. 800 hectareas, 1400 fuentes. El mayor palacio de Europa.', 'Pago EUR 21 / Gratis -18', true, true, 'Salir temprano — tour de medio dia minimo. Jardines incluidos.', 'https://maps.google.com/?q=Chateau+de+Versailles');
INSERT INTO lugares (ciudad, categoria, nombre, zona, descripcion, precio, es_gratis, requiere_reserva, tip, maps_url) VALUES ('Paris', 'musica', 'Moulin Rouge', 'Pigalle', 'El cabaret mas famoso del mundo desde 1889. Cancacan, plumas y lentejuelas. Espectaculo Feerie con 60 artistas.', 'Desde EUR 115 (solo show)', false, true, 'Reservar con meses de anticipacion. La cena es cara y prescindible.', 'https://maps.google.com/?q=Moulin+Rouge+Paris');
INSERT INTO lugares (ciudad, categoria, nombre, zona, descripcion, precio, es_gratis, requiere_reserva, tip, maps_url) VALUES ('Paris', 'musica', 'Olympia', '9eme arrondissement', 'La sala de conciertos mas legendaria de Francia. Aqui debutaron Edith Piaf, Jacques Brel y Los Beatles en Europa.', 'Entrada varia segun artista', false, false, 'Revisar agenda en febrero — siempre hay algo bueno.', 'https://maps.google.com/?q=Olympia+Paris');
INSERT INTO lugares (ciudad, categoria, nombre, zona, descripcion, precio, es_gratis, requiere_reserva, tip, maps_url) VALUES ('Paris', 'musica', 'La Cigale', 'Pigalle', 'Sala art-deco de 2000 personas. Rock, indie, electronica internacional. Acustica perfecta.', 'Entrada varia segun artista', false, false, 'Ubicada en Pigalle, cerca del Moulin Rouge.', 'https://maps.google.com/?q=La+Cigale+Paris');
INSERT INTO lugares (ciudad, categoria, nombre, zona, descripcion, precio, es_gratis, requiere_reserva, tip, maps_url) VALUES ('Paris', 'musica', 'Philharmonie de Paris', 'La Villette', 'Sala de conciertos de clase mundial disenada por Jean Nouvel. Programa clasico y jazz de primer nivel.', 'Entrada desde EUR 10', false, false, 'El edificio en si es una obra arquitectonica.', 'https://maps.google.com/?q=Philharmonie+Paris');
INSERT INTO lugares (ciudad, categoria, nombre, zona, descripcion, precio, es_gratis, requiere_reserva, tip, maps_url) VALUES ('Bruselas', 'miradores', 'Atomium', 'Laeken', 'Estructura futurista en forma de atomo de hierro gigantesco, construida para la Expo 1958. Vista panoramica desde la esfera superior.', 'Pago EUR 16 adulto / EUR 9 nino', false, false, 'A 15 min del centro en metro. Los ninos flipan con el ascensor tubular.', 'https://maps.google.com/?q=Atomium+Brussels');
INSERT INTO lugares (ciudad, categoria, nombre, zona, descripcion, precio, es_gratis, requiere_reserva, tip, maps_url) VALUES ('Bruselas', 'miradores', 'Palais de Justice — Terraza', 'Marolles', 'Tribunales neoclasicos enormes (1883) con terraza libre. Vista sobre los tejados de Bruselas hacia la Grand-Place.', 'Gratis', true, false, 'Acceso libre en horario de oficina.', 'https://maps.google.com/?q=Palais+de+Justice+Brussels');
INSERT INTO lugares (ciudad, categoria, nombre, zona, descripcion, precio, es_gratis, requiere_reserva, tip, maps_url) VALUES ('Bruselas', 'miradores', 'Place Royale — Barrio Real', 'Mont des Arts', 'Centro neoclasico de Bruselas. Vista sobre el skyline de la ciudad baja. Rodeado de los mejores museos.', 'Gratis', true, false, 'En febrero puede haber nieve — el lugar mas fotografiado nevado.', 'https://maps.google.com/?q=Place+Royale+Brussels');
INSERT INTO lugares (ciudad, categoria, nombre, zona, descripcion, precio, es_gratis, requiere_reserva, tip, maps_url) VALUES ('Bruselas', 'bares', 'Delirium Cafe', 'Centro historico', 'Bar con mas de 3000 tipos de cerveza segun el Libro Guinness. La cerveza Delirium Tremens (rosa con elefantes) es iconica.', 'Cerveza ~EUR 4-7', false, false, 'Llegar antes de las 22hs o hay fila para entrar.', 'https://maps.google.com/?q=Delirium+Cafe+Brussels');
INSERT INTO lugares (ciudad, categoria, nombre, zona, descripcion, precio, es_gratis, requiere_reserva, tip, maps_url) VALUES ('Bruselas', 'bares', 'A la Mort Subite', 'Centro historico', 'Pub belga de 1910 con interior art deco intacto. Especialidad: lambic y gueuze (cervezas de fermentacion espontanea).', 'Cerveza ~EUR 3-5', false, false, 'El lambic framboise (frambuesa) es perfecto para no beerlovers.', 'https://maps.google.com/?q=A+la+Mort+Subite+Brussels');
INSERT INTO lugares (ciudad, categoria, nombre, zona, descripcion, precio, es_gratis, requiere_reserva, tip, maps_url) VALUES ('Bruselas', 'bares', 'Moeder Lambic Fontainas', 'Saint-Gilles', 'Bar de culto con 50 cervezas de barril rotativas. Solo cervezas belgas independientes, nada industrial.', 'Cerveza ~EUR 4-8', false, false, 'Pedir recomendacion al barman — son expertos apasionados.', 'https://maps.google.com/?q=Moeder+Lambic+Fontainas+Brussels');
INSERT INTO lugares (ciudad, categoria, nombre, zona, descripcion, precio, es_gratis, requiere_reserva, tip, maps_url) VALUES ('Bruselas', 'bares', 'Mappa Mundo', 'Rue du Marche au Charbon', 'Bar cosmopolita en la calle mas animada del centro. Mezcla de locales y viajeros.', 'Cerveza/Coctel ~EUR 4-8', false, false, 'La rue du Marche au Charbon tiene 10 bares seguidos — ideal para ir de bar en bar.', 'https://maps.google.com/?q=Mappa+Mundo+Brussels');
INSERT INTO lugares (ciudad, categoria, nombre, zona, descripcion, precio, es_gratis, requiere_reserva, tip, maps_url) VALUES ('Bruselas', 'iconicos', 'Grand-Place', 'Centro historico', 'Una de las plazas mas hermosas del mundo segun Victor Hugo. UNESCO. Guildhalls barrocos del s.XVII. De noche iluminada.', 'Gratis', true, false, 'Verla de dia Y de noche — la iluminacion nocturna es espectacular.', 'https://maps.google.com/?q=Grand-Place+Brussels');
INSERT INTO lugares (ciudad, categoria, nombre, zona, descripcion, precio, es_gratis, requiere_reserva, tip, maps_url) VALUES ('Bruselas', 'iconicos', 'Manneken Pis', 'Centro historico', 'La estatuilla mas famosa de Bruselas: un nino orinando. Ironico simbolo de la identidad belga. Suele estar disfrazado.', 'Gratis', true, false, 'A 2 cuadras de la Grand-Place. Buscar la vitrina con los 1000 trajes que tiene.', 'https://maps.google.com/?q=Manneken+Pis+Brussels');
INSERT INTO lugares (ciudad, categoria, nombre, zona, descripcion, precio, es_gratis, requiere_reserva, tip, maps_url) VALUES ('Bruselas', 'iconicos', 'Musee Magritte', 'Mont des Arts', 'La coleccion mas grande del mundo del surrealista belga Rene Magritte. El hombre del bombin y la manzana en contexto.', 'Pago EUR 15 adulto / Gratis -18', true, false, 'Combinarlo con la visita al barrio royal — ambos en Mont des Arts.', 'https://maps.google.com/?q=Musee+Magritte+Brussels');
INSERT INTO lugares (ciudad, categoria, nombre, zona, descripcion, precio, es_gratis, requiere_reserva, tip, maps_url) VALUES ('Bruselas', 'iconicos', 'Barrio de las Marolles', 'Marolles', 'Barrio popular y bohemio. El mercado del Jeu de Balle: 2000 puestos de antiguedades y ropa vintage todos los dias.', 'Gratis', true, false, 'El mercado abre a las 6am — los mejores objetos se van antes de las 9.', 'https://maps.google.com/?q=Jeu+de+Balle+Brussels');
INSERT INTO lugares (ciudad, categoria, nombre, zona, descripcion, precio, es_gratis, requiere_reserva, tip, maps_url) VALUES ('Bruselas', 'musica', 'Ancienne Belgique (AB)', 'Centro historico', 'La sala de conciertos mas importante de Belgica. Indie, rock, folk internacional. Acustica impecable.', 'Entrada varia segun artista', false, false, 'Revisar agenda — es una noche sola en Bruselas, vale buscar algo.', 'https://maps.google.com/?q=Ancienne+Belgique+Brussels');
INSERT INTO lugares (ciudad, categoria, nombre, zona, descripcion, precio, es_gratis, requiere_reserva, tip, maps_url) VALUES ('Bruselas', 'musica', 'Bozar', 'Mont des Arts', 'Centro de bellas artes con programa de clasica, jazz y musica experimental de clase mundial.', 'Entrada desde EUR 10', false, false, 'El edificio art-deco de Victor Horta es patrimonio en si mismo.', 'https://maps.google.com/?q=Bozar+Brussels');
INSERT INTO lugares (ciudad, categoria, nombre, zona, descripcion, precio, es_gratis, requiere_reserva, tip, maps_url) VALUES ('Roma', 'miradores', 'Gianicolo', 'Trastevere', 'La mejor vista panoramica de Roma, gratis. Colina con canon que dispara a mediodia (tradicion desde 1846).', 'Gratis', true, false, 'Ir al mediodia para ver el canon — los ninos quedan impactados.', 'https://maps.google.com/?q=Gianicolo+Roma');
INSERT INTO lugares (ciudad, categoria, nombre, zona, descripcion, precio, es_gratis, requiere_reserva, tip, maps_url) VALUES ('Roma', 'miradores', 'Castel Sant''Angelo — Terraza', 'Prati', 'Fortaleza del siglo II convertida en castillo papal. La terraza ofrece vista sobre el Tiber, el Vaticano y el centro historico.', 'Pago EUR 15 adulto / Gratis -18 UE', true, false, 'Subir al atardecer para los mejores colores sobre el Vaticano.', 'https://maps.google.com/?q=Castel+Sant+Angelo+Roma');
INSERT INTO lugares (ciudad, categoria, nombre, zona, descripcion, precio, es_gratis, requiere_reserva, tip, maps_url) VALUES ('Roma', 'miradores', 'Pincio — Terraza del Pincio', 'Villa Borghese', 'Terraza romantica dentro del parque Villa Borghese. Vista clasica sobre la Piazza del Popolo y las cupulas de Roma.', 'Gratis', true, false, 'A 10 min caminando desde Piazza di Spagna. Perfecto para picnic.', 'https://maps.google.com/?q=Terrazza+del+Pincio+Roma');
INSERT INTO lugares (ciudad, categoria, nombre, zona, descripcion, precio, es_gratis, requiere_reserva, tip, maps_url) VALUES ('Roma', 'miradores', 'Vittoriano — Altare della Patria', 'Centro Storico', 'El ''pastel de bodas'' del centro. Ascensor hasta la terraza con vista 360 sobre los Foros, el Capitolio y el skyline.', 'Ascensor Pago ~EUR 7', false, false, 'El ascensor exterior es la experiencia — vistas increibles en ascenso.', 'https://maps.google.com/?q=Altare+della+Patria+Roma');
INSERT INTO lugares (ciudad, categoria, nombre, zona, descripcion, precio, es_gratis, requiere_reserva, tip, maps_url) VALUES ('Roma', 'bares', 'Freni e Frizioni', 'Trastevere', 'El aperitivo aperol con buffet incluido mas famoso de Roma. En un garage vintage reconvertido con jardin.', 'Aperitivo ~EUR 10 (incluye buffet)', false, false, 'Llegar entre 18:30-19:30 para el aperitivo — buffet abundante.', 'https://maps.google.com/?q=Freni+e+Frizioni+Roma');
INSERT INTO lugares (ciudad, categoria, nombre, zona, descripcion, precio, es_gratis, requiere_reserva, tip, maps_url) VALUES ('Roma', 'bares', 'Bar San Calisto', 'Trastevere', 'El bar mas humilde y genuino de Trastevere. Grappa, vino local y conversacion con romanos de toda la vida.', 'Consumicion ~EUR 2-4', false, false, 'Sin turistas, todo locales — el bar ''secreto'' que no sale en guias.', 'https://maps.google.com/?q=Bar+San+Calisto+Trastevere+Roma');
INSERT INTO lugares (ciudad, categoria, nombre, zona, descripcion, precio, es_gratis, requiere_reserva, tip, maps_url) VALUES ('Roma', 'bares', 'Rec 23', 'Pigneto', 'Cocteleria artesanal en el barrio mas hipster de Roma. Diseno industrial, DJ sets y cocteles de autor.', 'Cocteles ~EUR 10-14', false, false, 'El barrio Pigneto es la alternativa romana a Brooklyn.', 'https://maps.google.com/?q=Rec+23+Pigneto+Roma');
INSERT INTO lugares (ciudad, categoria, nombre, zona, descripcion, precio, es_gratis, requiere_reserva, tip, maps_url) VALUES ('Roma', 'bares', 'Il Sorpasso', 'Prati', 'Bar de dia y bistro de noche. Vermut y aperitivos perfectos antes de cenar. Muy popular entre romanos.', 'Aperitivo ~EUR 8-12', false, false, 'El barrio Prati es tranquilo y autentico, cerca del Vaticano.', 'https://maps.google.com/?q=Il+Sorpasso+Roma');
INSERT INTO lugares (ciudad, categoria, nombre, zona, descripcion, precio, es_gratis, requiere_reserva, tip, maps_url) VALUES ('Roma', 'iconicos', 'Coliseo + Foro Romano + Palatino', 'Centro Storico', 'El anfiteatro del siglo I donde luchaban los gladiadores. El ticket incluye Foro Romano y Monte Palatino — medio dia de historia.', 'Pago EUR 18 (entrada combinada)', false, true, 'Reservar con 3 meses de anticipacion — se agota. Entrar por el lado del Meta Sudans.', 'https://maps.google.com/?q=Colosseo+Roma');
INSERT INTO lugares (ciudad, categoria, nombre, zona, descripcion, precio, es_gratis, requiere_reserva, tip, maps_url) VALUES ('Roma', 'iconicos', 'Panteón', 'Piazza della Rotonda', 'Templo romano del siglo II perfectamente conservado. La cupula de 43m con el oculo abierto al cielo sigue siendo un prodigio ingenieril.', 'Gratis con reserva obligatoria', true, true, 'La reserva es gratuita pero obligatoria online. Lluvia + oculo = espectaculo.', 'https://maps.google.com/?q=Pantheon+Roma');
INSERT INTO lugares (ciudad, categoria, nombre, zona, descripcion, precio, es_gratis, requiere_reserva, tip, maps_url) VALUES ('Roma', 'iconicos', 'Fontana di Trevi', 'Trevi', 'La fuente barroca mas grande de Roma (1762). Tirar una moneda garantiza el regreso a Roma segun la leyenda.', 'Gratis', true, false, 'Ir antes de las 8am o despues de las 23pm para evitar la multitud.', 'https://maps.google.com/?q=Fontana+di+Trevi+Roma');
INSERT INTO lugares (ciudad, categoria, nombre, zona, descripcion, precio, es_gratis, requiere_reserva, tip, maps_url) VALUES ('Roma', 'iconicos', 'Trastevere', 'Trastevere', 'El barrio mas romantico de Roma. Callecitas medievales, trattorias con mesas en la calle, iglesias barrocas.', 'Gratis', true, false, 'Cenar aqui — la trattoria Da Enzo al 29 tiene la cacio e pepe definitiva.', 'https://maps.google.com/?q=Trastevere+Roma');
INSERT INTO lugares (ciudad, categoria, nombre, zona, descripcion, precio, es_gratis, requiere_reserva, tip, maps_url) VALUES ('Roma', 'iconicos', 'Ciudad del Vaticano + Capilla Sixtina', 'Vaticano', 'La Creacion de Miguel Angel en el techo. La basilica mas grande del mundo. Los Museos Vaticanos tienen 54km de salas.', 'Pago EUR 20 / Gratis primer domingo del mes', true, true, 'Reservar online obligatorio. Cola sin reserva: 2-3 horas. Con reserva: entrar directo.', 'https://maps.google.com/?q=Vatican+Museum+Roma');
INSERT INTO lugares (ciudad, categoria, nombre, zona, descripcion, precio, es_gratis, requiere_reserva, tip, maps_url) VALUES ('Roma', 'iconicos', 'Piazza Navona', 'Centro Storico', 'La plaza mas bella de Roma. Tres fuentes de Bernini incluyendo la Fuente de los Cuatro Rios.', 'Gratis', true, false, 'El gelato de La Romana (a 2 cuadras) es el mejor del centro.', 'https://maps.google.com/?q=Piazza+Navona+Roma');
INSERT INTO lugares (ciudad, categoria, nombre, zona, descripcion, precio, es_gratis, requiere_reserva, tip, maps_url) VALUES ('Roma', 'iconicos', 'Campo de'' Fiori', 'Centro Storico', 'Mercado matutino con fruta y flores desde el s.XVI. De noche se transforma en epicentro de la vida nocturna.', 'Gratis', true, false, 'Mercado de 8am a 13pm. De noche: terrazas y aperitivos.', 'https://maps.google.com/?q=Campo+de+Fiori+Roma');
INSERT INTO lugares (ciudad, categoria, nombre, zona, descripcion, precio, es_gratis, requiere_reserva, tip, maps_url) VALUES ('Roma', 'musica', 'Alexanderplatz Jazz Club', 'Prati', 'El club de jazz mas famoso de Roma, activo desde 1984. Musicos internacionales todos los miercoles a domingos.', 'Entrada ~EUR 10-20', false, true, 'Reservar mesa — se llena los fines de semana.', 'https://maps.google.com/?q=Alexanderplatz+Jazz+Club+Roma');
INSERT INTO lugares (ciudad, categoria, nombre, zona, descripcion, precio, es_gratis, requiere_reserva, tip, maps_url) VALUES ('Roma', 'musica', 'Big Mama', 'Trastevere', 'Blues y soul en vivo desde 1984 en una bodega de Trastevere. El antro de referencia del blues romano.', 'Entrada ~EUR 5-10', false, false, 'Combinarlo con la cena en Trastevere — abre a las 21hs.', 'https://maps.google.com/?q=Big+Mama+Trastevere+Roma');
INSERT INTO lugares (ciudad, categoria, nombre, zona, descripcion, precio, es_gratis, requiere_reserva, tip, maps_url) VALUES ('Roma', 'musica', 'Auditorium Parco della Musica', 'Flaminio', 'Complejo musical de Renzo Piano. Tres salas con programa de jazz, clasica y world music de primer nivel.', 'Entrada desde EUR 15', false, false, 'Revisar programa en auditorium.com — siempre hay algo interesante en febrero.', 'https://maps.google.com/?q=Auditorium+Parco+della+Musica+Roma');
INSERT INTO lugares (ciudad, categoria, nombre, zona, descripcion, precio, es_gratis, requiere_reserva, tip, maps_url) VALUES ('Madrid', 'miradores', 'Circulo de Bellas Artes — Rooftop', 'Centro', 'La mejor terraza de Madrid. Vista 360 sobre los tejados y la Gran Via. Con bar y ambiente cultural.', 'Pago EUR 5 (incluye consumicion)', false, false, 'Al atardecer es magico — la Gran Via iluminada es espectacular.', 'https://maps.google.com/?q=Circulo+de+Bellas+Artes+Madrid');
INSERT INTO lugares (ciudad, categoria, nombre, zona, descripcion, precio, es_gratis, requiere_reserva, tip, maps_url) VALUES ('Madrid', 'miradores', 'El Corte Ingles Callao — Terraza', 'Gran Via', 'Terraza del 9no piso con vista directa sobre la Gran Via y el skyline de Madrid. Acceso libre.', 'Gratis (consumicion opcional)', true, false, 'El restaurante del techo tiene las mejores vistas del centro — abre al mediodia.', 'https://maps.google.com/?q=El+Corte+Ingles+Callao+Madrid');
INSERT INTO lugares (ciudad, categoria, nombre, zona, descripcion, precio, es_gratis, requiere_reserva, tip, maps_url) VALUES ('Madrid', 'miradores', 'Parque del Retiro', 'Retiro', 'El gran pulmon verde de Madrid. 350 hectareas con palacio de cristal, lago con barcas y jardines.', 'Gratis', true, false, 'El Palacio de Cristal tiene exposiciones gratuitas. Las barcas estan disponibles en febrero.', 'https://maps.google.com/?q=Parque+del+Retiro+Madrid');
INSERT INTO lugares (ciudad, categoria, nombre, zona, descripcion, precio, es_gratis, requiere_reserva, tip, maps_url) VALUES ('Madrid', 'bares', 'Salmon Guru', 'Centro (Lavapies)', 'Elegido uno de los 50 mejores bares del mundo. Cocteles de autor con tecnica de vanguardia.', 'Cocteles ~EUR 14-20', false, true, 'Reservar para fin de semana — entre semana suele haber lugar.', 'https://maps.google.com/?q=Salmon+Guru+Madrid');
INSERT INTO lugares (ciudad, categoria, nombre, zona, descripcion, precio, es_gratis, requiere_reserva, tip, maps_url) VALUES ('Madrid', 'bares', 'Bodega de los Secretos', 'Centro (Sol)', 'Cocteleria y restaurante en bodega medieval del siglo XIII. 800 anos de historia bajo Madrid.', 'Cocteles ~EUR 12-16', false, true, 'El espacio subterraneo es unico — vale la pena aunque solo sea a tomar algo.', 'https://maps.google.com/?q=Bodega+de+los+Secretos+Madrid');
INSERT INTO lugares (ciudad, categoria, nombre, zona, descripcion, precio, es_gratis, requiere_reserva, tip, maps_url) VALUES ('Madrid', 'bares', 'Mercado de San Miguel', 'Centro (Sol)', 'Mercado gourmet del s.XX en estructura de hierro. Tapas, ostras, vinos y vermut entre locales y turistas.', 'Tapa ~EUR 2-5 / Vino ~EUR 3-5', false, false, 'El mejor vermut del mercado: Bodegas Marin. Ir entre 12 y 14hs.', 'https://maps.google.com/?q=Mercado+de+San+Miguel+Madrid');
INSERT INTO lugares (ciudad, categoria, nombre, zona, descripcion, precio, es_gratis, requiere_reserva, tip, maps_url) VALUES ('Madrid', 'bares', 'El Tigre', 'Chueca', 'Bar legendario de tapas abundantes y gratuitas con cada cana. Cerveza y plato de jamon incluido.', 'Cerveza ~EUR 3 (tapa gratis)', true, false, 'No es glamoroso pero las tapas son abundantes y muy economico.', 'https://maps.google.com/?q=El+Tigre+Madrid+Chueca');
INSERT INTO lugares (ciudad, categoria, nombre, zona, descripcion, precio, es_gratis, requiere_reserva, tip, maps_url) VALUES ('Madrid', 'bares', 'Sala Equis', 'Lavapies', 'Cine-bar alternativo en patio interior del s.XIX. Vermut los sabados, proyecciones de cine independiente.', 'Consumicion ~EUR 5-8', false, false, 'El patio descubierto es especial incluso en invierno con braseros.', 'https://maps.google.com/?q=Sala+Equis+Madrid');
INSERT INTO lugares (ciudad, categoria, nombre, zona, descripcion, precio, es_gratis, requiere_reserva, tip, maps_url) VALUES ('Madrid', 'iconicos', 'Museo del Prado', 'Paseo del Arte', 'Uno de los museos mas importantes del mundo. Velazquez (Las Meninas), Goya (Los Fusilamientos), El Greco. 8000 obras.', 'Pago EUR 15 / Gratis -18 / Gratis ultimas 2hs', true, false, 'Gratis ultimas 2 horas pero con cola larga. Dedicarle minimo 3 horas.', 'https://maps.google.com/?q=Museo+del+Prado+Madrid');
INSERT INTO lugares (ciudad, categoria, nombre, zona, descripcion, precio, es_gratis, requiere_reserva, tip, maps_url) VALUES ('Madrid', 'iconicos', 'Museo Reina Sofia', 'Paseo del Arte', 'El Guernica de Picasso. Dali, Miro y las vanguardias del siglo XX.', 'Pago EUR 12 / Gratis -18 / Gratis sabados 19hs', true, false, 'El Guernica esta en la segunda planta — sin perderlo.', 'https://maps.google.com/?q=Museo+Reina+Sofia+Madrid');
INSERT INTO lugares (ciudad, categoria, nombre, zona, descripcion, precio, es_gratis, requiere_reserva, tip, maps_url) VALUES ('Madrid', 'iconicos', 'El Rastro', 'La Latina / Lavapies', 'El mercadillo mas famoso de Espana, desde el s.XVIII. 3500 puestos de antiguedades, ropa vintage, viniles.', 'Gratis', true, false, 'Solo domingos y festivos — 14 feb es domingo. Ir antes de las 11hs.', 'https://maps.google.com/?q=El+Rastro+Madrid');
INSERT INTO lugares (ciudad, categoria, nombre, zona, descripcion, precio, es_gratis, requiere_reserva, tip, maps_url) VALUES ('Madrid', 'iconicos', 'Barrio de las Letras', 'Centro historico', 'Barrio del Siglo de Oro. Versos de Lope de Vega y Quevedo grabados en las calles. Cervantes murio a una cuadra.', 'Gratis', true, false, 'La Calle Huertas tiene los mejores bares del barrio y mucho ambiente.', 'https://maps.google.com/?q=Barrio+de+las+Letras+Madrid');
INSERT INTO lugares (ciudad, categoria, nombre, zona, descripcion, precio, es_gratis, requiere_reserva, tip, maps_url) VALUES ('Madrid', 'iconicos', 'Palacio Real', 'Opera', 'El palacio real mas grande de Europa Occidental. 3418 habitaciones, armeria real, jardines de Sabatini.', 'Pago EUR 14 adulto / EUR 7 nino', false, false, 'El cambio de guardia es el primer miercoles del mes — febrero tiene uno.', 'https://maps.google.com/?q=Palacio+Real+Madrid');
INSERT INTO lugares (ciudad, categoria, nombre, zona, descripcion, precio, es_gratis, requiere_reserva, tip, maps_url) VALUES ('Madrid', 'iconicos', 'Mercado de San Anton', 'Chueca', 'Mercado gourmet de tres plantas en el barrio de Chueca. Productos gourmet, restaurantes y terraza en el techo.', 'Gratis entrada', true, false, 'La terraza del techo tiene vistas al barrio y es mas tranquila que San Miguel.', 'https://maps.google.com/?q=Mercado+San+Anton+Chueca+Madrid');
INSERT INTO lugares (ciudad, categoria, nombre, zona, descripcion, precio, es_gratis, requiere_reserva, tip, maps_url) VALUES ('Madrid', 'musica', 'Sala El Sol', 'Centro (Gran Via)', 'Sala emblematica de La Movida Madrilena. Abierta desde 1979, aqui se forjo el rock espanol. Indie, pop, electronica.', 'Entrada ~EUR 8-15', false, false, 'Revisar agenda en febrero — es una de las salas mas historicas de Madrid.', 'https://maps.google.com/?q=Sala+El+Sol+Madrid');
INSERT INTO lugares (ciudad, categoria, nombre, zona, descripcion, precio, es_gratis, requiere_reserva, tip, maps_url) VALUES ('Madrid', 'musica', 'Teatro Real', 'Opera', 'La opera mas importante de Espana. Programa de primer nivel mundial con directores y cantantes internacionales.', 'Entrada desde EUR 10 (paraiso) hasta EUR 250', false, true, 'Las entradas de paraiso (EUR 10-20) son la mejor relacion calidad-precio de Madrid.', 'https://maps.google.com/?q=Teatro+Real+Madrid');
INSERT INTO lugares (ciudad, categoria, nombre, zona, descripcion, precio, es_gratis, requiere_reserva, tip, maps_url) VALUES ('Madrid', 'musica', 'Sala Clamores', 'Almagro', 'El club de jazz de referencia en Madrid desde 1978. Ambiente intimo, buena acustica, programa constante.', 'Entrada ~EUR 8-12', false, false, 'Los martes son los conciertos mas economicos con musicos residentes.', 'https://maps.google.com/?q=Sala+Clamores+Madrid');
INSERT INTO lugares (ciudad, categoria, nombre, zona, descripcion, precio, es_gratis, requiere_reserva, tip, maps_url) VALUES ('Madrid', 'musica', 'Joy Eslava', 'Centro (Sol)', 'Discoteca en el teatro historico Eslava del siglo XIX. Tres pisos, electronica y pop espanol, mix de edades.', 'Entrada ~EUR 15-20 (incluye consumicion)', false, false, 'El edificio neoclasico con la pista de baile abajo es un lugar unico.', 'https://maps.google.com/?q=Joy+Eslava+Madrid');